import { Component, Input, OnChanges, SimpleChanges, ChangeDetectionStrategy, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-datatable',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './datatable.component.html',
  styleUrls: ['./datatable.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class DataTableComponent implements OnChanges {
  @Input() data: any[] = [];

  filteredData: any[] = []; // full filtered data

  // Pagination settings
  pageSize = 10;
  currentPage = 1;

  filterText = '';
  columns: string[] = [];

  @Output() rowSelected = new EventEmitter<any>();

  selectedRow: any = null;

  selectRow(row: any): void {
    this.selectedRow = row;
    this.rowSelected.emit(row);
  }


  ngOnChanges(changes: SimpleChanges) {
    if (changes['data']) {
      this.columns = this.data.length ? Object.keys(this.data[0]) : [];
      this.applyFilter();
    }
  }

  applyFilter() {
    const text = this.filterText?.toLowerCase() ?? '';
    if (!text) {
      this.filteredData = [...this.data];
    } else {
      const normalize = (s: string) => s.normalize('NFD').replace(/\p{Diacritic}/gu, '');
      this.filteredData = this.data.filter(row =>
        Object.values(row).some(v => {
          const str = typeof v === 'string' ? v : String(v);
          return normalize(str.toLowerCase()).includes(normalize(text));
        })
      );
    }
    this.adjustCurrentPage();
  }

  onFilterChange(event: Event) {
    const input = event.target as HTMLInputElement;
    this.filterText = input.value;
    this.applyFilter();
  }

  // Pagination helpers
  get totalPages(): number {
    return Math.ceil(this.filteredData.length / this.pageSize) || 1;
  }

  get paginatedData(): any[] {
    const startIdx = (this.currentPage - 1) * this.pageSize;
    return this.filteredData.slice(startIdx, startIdx + this.pageSize);
  }

  prevPage() {
    if (this.currentPage > 1) {
      this.currentPage--;
    }
  }

  nextPage() {
    if (this.currentPage < this.totalPages) {
      this.currentPage++;
    }
  }

  private adjustCurrentPage() {
    const maxPage = this.totalPages;
    if (this.currentPage > maxPage) {
      this.currentPage = maxPage;
    }
  }

  exportCsv() {
    if (!this.filteredData.length) return;

    const headers = Object.keys(this.data[0] || {});
    const csvRows = [headers.join(',')];
    for (const row of this.filteredData) {
      const csvRow = headers.map(h => {
        const val = row[h];
        if (typeof val === 'string') {
          // escape quotes
          return `"${val.replace(/"/g, '""')}"`;
        }
        return String(val);
      }).join(',');
      csvRows.push(csvRow);
    }
    const csvContent = csvRows.join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', 'data.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
}
